import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        int maxLength = 10; // Maximum length of the buffer
        char[] buffer = new char[maxLength]; // Buffer of fixed size

        int length = Math.min(userInput.length(), maxLength); // Limit input length to buffer size

        for (int i = 0; i < length; i++) {
            buffer[i] = userInput.charAt(i); // Copying user input into buffer with bounds checking
        }

        System.out.println("Buffer content: " + new String(buffer, 0, length));
    }
}

### Explanation:
취약유형: Buffer Overflow
